var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"어엉? 모르스? 뭐야, 그 이상한 이름은?","JPN":"ああん？　モールス？　なんだ、その変な名前は。","ENG":"What? Mors? What kind of name is that?","TWN":"什麼？莫爾斯？這是什麼奇怪的名字？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그것보다 너도 용병이냐? 이번 의뢰에 사람이 비는데 같이 갈래?","JPN":"それよりお前も傭兵なのか？　今度の依頼、席空いてるけど一緒に行くか？","ENG":"Hey, you a mercenary, too? There’s room for another on this commission, want to come along?","TWN":"不過你也是傭兵嗎？這次的委託人不夠，你要一起去嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"아……. 모르스. 기억하지. 요즘에야 뭐 별난 놈들이 많아서 묻히긴 했는데, 옛날엔 유명했지.","JPN":"あ……モールス。覚えてるよ。最近はまあ、変な奴らが多くて埋もれているけど、昔は有名だったな。","ENG":"Oh... Mors. I remember now! There're a lot of weirdos around now these days, but back in the day that name was pretty famous.","TWN":"喔……莫爾斯我有印象，可能最近奇怪的傢伙太多，所以大家有點忘記她，但以前是很有名的！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"가는 곳마다 재앙을 부른다던 녀석인데……. 솔직히 이 바닥 소문은 부풀려지기 마련이거든.","JPN":"行くところに災いを呼ぶ奴ってことだけど……正直ここんとこの噂って盛りすぎること多いだろ。","ENG":"Word is, anywhere she goes, disaster follows. Ehh, it’s probably just some rumor though, you know how those are.","TWN":"據說她所到之處就會引發災難……不過像這種傳言，都是誇大的成分居多啦！"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"아마 그냥 남들보다 좀 튀는 차림새에다 눈치 없이 이거저거 건드려서 그랬던 거 아닐까?","JPN":"たぶん他の奴より目立つ恰好で、あちらこちらを騒がせたからじゃないかね？","ENG":"It’s probably just because she looks so different than everyone else she gets noticed so often.","TWN":"或許她只是穿著比別人顯眼，然後又喜歡到處惹事生非，大家才會對她特別有印象吧？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"모르스라…….","JPN":"モールスか……","ENG":"Mors...","TWN":"莫爾斯……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"최근 어떤 손님에게서 비슷한 사람을 봤다는 이야기를 들은 적 있어.","JPN":"最近あるお客さんに、似たような人を見たって聞いたことがあるわ。","ENG":"Huh, I heard the other day from a customer that they saw someone fitting that description.","TWN":"我最近是有聽某位客人說，他有看到類似的人物。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"계약?","JPN":"契約？","ENG":"A contract?","TWN":"契約？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아니, 그렇게까지 대단한 정보는 또 아니거든.","JPN":"いや、そこまで大した情報ではないのよね。","ENG":"Nah. It wasn’t that much info.","TWN":"拜託，這又不是什麼厲害的消息。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"무슨 이유인지 몰라도 꼭 찾길 바랄게. 아가씨.","JPN":"理由はわからないけど見つかったらいいな。お嬢さん。","ENG":"Don’t know what you’re looking for, but I hope you find it, Lady!","TWN":"雖然不知道你為何要找她，但祝你早日找到她囉，小姐。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"……북방 합의체의 세력권에 숨어 있을 줄은 몰랐어.","JPN":"……北方合意体の縄張りに隠れてるとは思ってもいなかった。","ENG":"...Didn’t expect her to be hiding in the Northern Union’s sphere of influence.","TWN":"……沒想到你會躲在北方和議會的勢力範圍內。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"이성이 오락가락하는 그림자치고는 머리를 좀 굴렸군. 모르스.","JPN":"理性が曖昧なシャドウにしてはよく考えたな。モールス。","ENG":"You really put your brain to work though you’re a Shadow, didn’t you? Mors.","TWN":"以腦袋不清楚的暗影來說，你算是有在動腦的，莫爾斯。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나를 찾아온 것인가. 소녀여.","JPN":"我を訪ねて来たのか。少女よ。","ENG":"You came seeking me, girl?","TWN":"少女，你是來找我的嗎？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"용무는 듣지 않겠다. 이곳은 위험하니 어서 떠나라.","JPN":"用件は聞かぬ。ここは危ない、速やかにここを離れろ。","ENG":"It doesn’t matter what carries you here. This place is dangerous. You should leave.","TWN":"我不管你為何來找我，這個地方很危險，你快離開吧。"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"인간 따위를 걱정해 주니 그런 꼴이 되었다고 생각하지 않아?","JPN":"人間なんかを心配するからそんな様になったとは思わないのか？","ENG":"Don’t you think you ended up in such a miserable state because you care so much about humans?","TWN":"你不覺得，就是因為你太替人類著想，才會落得這般下場嗎？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MONTAGNE_ADMIN_NULL_GIRL","text":{"KOREA":"미니스트라라는 개체가 발생할 때도. 언변이 부족하면 행동으로라도 강제했어야지.","JPN":"ミニストラという個体が発生した時も。言葉で足りないなら強行すべきだった。","ENG":"Even when Ministra came into existence. If you aren’t that great a speaker you should have spoken with your actions.","TWN":"迷你斯特拉這個個體產生時也是，就算口才不好，起碼也要強制行動吧？"},"stage":{"bg":"WAREHOUSE_01","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_GIRL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};